#!/usr/bin/env bash
# c.sh — C 端夏令营 / 营地营期全流程（产品→获客→执行→复购） SOP walkthrough for 研学营地教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="研学营地教育"
WORKFLOW="C 端夏令营 / 营地营期全流程（产品→获客→执行→复购）"

usage() {
  cat <<EOF
c.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./c.sh             # interactive
  ./c.sh --dry-run
  ./c.sh --json
  ./c.sh --explain
  ./c.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "C 端夏令营 / 营地营期全流程（产品→获客→执行→复购）" 工作流。

一句话: 从「要在寒暑假旺季推出一款可售卖的营产品」走到「招满、安全办完、家长满意、产生续报与转介绍」的状态——本行业 C 端（家庭付费）的总 pipeline，盈利与口碑都押在这条线上。

入门 SOP 共 7 步, 失败模式自检 3 项。

相关心智模型:
  • 「研学是课程不是行程」——教育属性优先: 研学/营地的本体是**课程**（有学习目标—实施—评价闭环），不是**行程**（景点+讲解词）；从业者用「教育本质」作为对抗旅游化、获客化、速成化的立场锚与对客叙事。
  • 体验—反思闭环（Kolb 圈）——「经验无反思即旅游」: 学习不是「去过/动手过」就发生，而要走完「具体经验→反思观察→抽象概念化→主动实践」的圈；**「反思/复盘」环节的有无，是研学区别于旅游的命门工序**。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**产品设计+定价**：定主题、龄段、天数、营地、卖点与成本结构，出产品说明书。跳过后果：定位模糊、龄段混装，体验崩、退费多。 evidence: [W-S002]（LB/T 092 附录 C 产品说明书）"
  "**营期排期**：按营地容量与师资排档期、波次、人数上限。跳过后果：超容量挤兑安全与体验，或排期撞车导致师资不足。 evidence: [W-S008, W-S014]"
  "**获客（私域+短视频+本地生活）**：视频号/抖音/小红书内容种草→引流小程序/企微私域；美团/携程上架团购。跳过后果：旺季招不满，营地与师资空置即亏损。 evidence: [W-S018]"
  "**小程序报名缴费**：小程序展示+微信支付，金数据/腾讯收集表收报名+健康信息+监护人授权。跳过后果：报名信息缺健康/监护授权，营中突发无依据、合规风险。 evidence: [W-S002]"
  "**营前准备（物资/师资/营辅比）**：备物资、培训营辅、按**营辅比按年龄分级**配人。跳过后果：营辅比超标=安全红线违规；营辅未培训=带组失控。 evidence: [W-S014]"
  "**营期执行**：破冰建立团队→体验式课程（含反思）→每日复盘仪式→闭营典礼+成果展示。跳过后果：跳过复盘=「只玩没学」，家长感知不到教育价值。 evidence: [W-S020]（Kolb 反思环节）"
  "**家长反馈 → 续报/转介绍**：闭营即收反馈、推下一期与转介绍裂变。跳过后果：高满意度不转化为复购，获客成本无法摊薄，全靠重新买量。 evidence: [W-S019]"
)
declare -a FAILURE_MODES=(
  "**重旅游轻教育滑向「只游不学」**：用 OTA/本地生活的旅游逻辑做产品，跳过复盘与成果，被家长识破「就是带去玩」。→ 每日固定复盘仪式+闭营成果展，把教育价值「可视化」给家长。 evidence: [W-S020, W-S011]"
  "**营辅比/安全按学校师生比套用**：用班级 1:40 配营辅，低龄住宿营应到 1:6，超标即安全红线。→ 营辅比按 ACA 年龄分级排班，营前点验到位才开营。 evidence: [W-S014]"
  "**高满意度零转化**：办得好但不收反馈、不设转介绍机制，下一期又从零买量、获客成本压垮利润。→ 闭营即触发反馈+老带新+续报优惠的转介绍引擎。 evidence: [W-S019]"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "c-walkthrough"
fi
